def calculate_mad(numbers):
    if not numbers:
        return 0.0

    mean = sum(numbers) / len(numbers)
    mad = sum(abs(x - mean) for x in numbers) / len(numbers)

    return mad

def sum_product(numbers):
    if not numbers:
        return (0, 1)

    total_sum = 0
    total_product = 1

    for number in numbers:
        total_sum += number
        total_product *= number

    return (total_sum, total_product)

from typing import List

def rolling_max(numbers: List[int]) -> List[int]:
    if not numbers:
        return []

    max_so_far = numbers[0]
    rolling_max_list = [max_so_far]

    for num in numbers[1:]:
        if num > max_so_far:
            max_so_far = num
        rolling_max_list.append(max_so_far)

    return rolling_max_list

def longest(strings):
    if not strings:
        return None

    longest_string = max(strings, key=len)
    return longest_string

def gcd(a, b):
    # Handle the case where either a or b is zero
    if a == 0:
        return abs(b)
    if b == 0:
        return abs(a)

    # Use the Euclidean algorithm to find the GCD
    while b != 0:
        a, b = b, a % b

    return a

def string_sequence(n):
    if n < 0:
        return ""
    elif n == 0:
        return "0"
    else:
        return " ".join(str(i) for i in range(n + 1))

def parse_music(music_string):
    # Split the input string by '|' to separate different notes
    notes = music_string.split('|')

    # Initialize an empty list to store the number of beats for each note
    beats = []

    # Iterate over each note in the split list
    for note in notes:
        # Remove any leading or trailing whitespace from the note
        note = note.strip()

        # Determine the number of beats based on the note character
        if note == 'o':
            beats.append(4)
        elif note == 'o|':
            beats.append(2)
        elif note == '.|':
            beats.append(1)
        else:
            # Handle unexpected characters by raising an error
            raise ValueError(f"Unexpected character '{note}' in input string.")

    return beats

def how_many_times(string, substring):
    if not string or not substring:
        return 0

    count = 0
    start = 0

    while start <= len(string) - len(substring):
        if string[start:start + len(substring)] == substring:
            count += 1
        start += 1

    return count

def scale_to_unit(numbers):
    if len(numbers) < 2:
        raise ValueError("The list must contain at least two elements.")

    min_num = min(numbers)
    max_num = max(numbers)

    # Avoid division by zero if all numbers are the same
    if min_num == max_num:
        return [0.0] * len(numbers)

    scaled_numbers = [(x - min_num) / (max_num - min_num) for x in numbers]
    return scaled_numbers

