def largest_divisor(n):
    """
    Find the largest divisor of a given number n that is smaller than n.

    :param n: An integer representing the number for which to find the largest divisor.
    :return: An integer representing the largest divisor of n that is smaller than n.
    """
    if n <= 1:
        return 0
    for i in range(n - 1, 0, -1):
        if n % i == 0:
            return i
    return 1  # This line is technically unreachable due to the loop condition

def remove_duplicates(numbers):
    seen = set()
    result = []
    for number in numbers:
        if number not in seen:
            seen.add(number)
            result.append(number)
    return result

import math

def is_prime(n):
    """
    Determine if a given integer is a prime number.

    :param n: An integer representing the number to check for primality.
    :return: A boolean value indicating whether `n` is a prime number.
    """
    if n < 2:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    max_divisor = int(math.sqrt(n))
    for divisor in range(3, max_divisor + 1, 2):
        if n % divisor == 0:
            return False
    return True

def unique(l):
    # Use a set to remove duplicates and then convert it back to a sorted list
    return sorted(set(l))

def max_element(l):
    if not l:
        return None  # Return None for an empty list
    max_val = l[0]  # Initialize max_val with the first element of the list
    for num in l:
        if num > max_val:
            max_val = num  # Update max_val if a larger number is found
    return max_val

def count_sevens(n):
    if n <= 0:
        return 0

    count = 0
    for i in range(1, n):
        if i % 11 == 0 or i % 13 == 0:
            count += str(i).count('7')

    return count

def is_prime(num):
    """Check if a number is prime."""
    if num <= 1:
        return False
    if num <= 3:
        return True
    if num % 2 == 0 or num % 3 == 0:
        return False
    i = 5
    while i * i <= num:
        if num % i == 0 or num % (i + 2) == 0:
            return False
        i += 6
    return True

def nth_prime_fibonacci(n):
    """Return the n-th Fibonacci number that is also a prime number."""
    if n < 1:
        raise ValueError("Input must be a positive integer.")

    fib1, fib2 = 0, 1
    count = 0

    while True:
        fib_next = fib1 + fib2
        fib1, fib2 = fib2, fib_next

        if is_prime(fib_next):
            count += 1
            if count == n:
                return fib_next

