def correct_bracketing(brackets):
    # Initialize a counter to track the balance of brackets
    balance = 0

    # Iterate over each character in the input string
    for char in brackets:
        # If the character is '<', increment the balance
        if char == '<':
            balance += 1
        # If the character is '>', decrement the balance
        elif char == '>':
            balance -= 1

        # If at any point the balance is negative, it means there's a closing bracket without a matching opening bracket
        if balance < 0:
            return False

    # If the balance is zero at the end, all brackets are matched
    return balance == 0

def is_monotonic(l):
    if not l:
        return True

    increasing = decreasing = True

    for i in range(1, len(l)):
        if l[i] > l[i - 1]:
            decreasing = False
        elif l[i] < l[i - 1]:
            increasing = False

    return increasing or decreasing

def largest_prime_factor(n):
    """
    Return the largest prime factor of a given integer n, assuming n is greater than 1 and is not a prime number.

    :param n: An integer greater than 1 and not a prime number.
    :return: The largest prime factor of n.
    """
    def is_prime(num):
        """Check if a number is prime."""
        if num <= 1:
            return False
        if num <= 3:
            return True
        if num % 2 == 0 or num % 3 == 0:
            return False
        i = 5
        while i * i <= num:
            if num % i == 0 or num % (i + 2) == 0:
                return False
            i += 6
        return True

    largest_factor = -1
    # Check for smallest prime factor
    for i in range(2, int(n**0.5) + 1):
        while n % i == 0:
            largest_factor = i
            n //= i
    # If n is still greater than 2, then it is a prime number
    if n > 2:
        largest_factor = n
    return largest_factor

