def correct_bracketing(brackets):
    # Initialize a counter to track the balance of parentheses
    balance = 0

    # Iterate over each character in the input string
    for char in brackets:
        # If the character is an opening bracket, increment the balance
        if char == '(':
            balance += 1
        # If the character is a closing bracket, decrement the balance
        elif char == ')':
            balance -= 1

        # If at any point the balance is negative, it means there's a closing bracket without a matching opening bracket
        if balance < 0:
            return False

    # If the balance is zero at the end, all opening brackets have matching closing brackets
    return balance == 0

def derivative(xs):
    # Check if the input list is empty
    if not xs:
        return []

    # Initialize the result list with zeros
    result = [0] * (len(xs) - 1)

    # Calculate the derivative coefficients
    for i in range(1, len(xs)):
        result[i - 1] = xs[i] * i

    return result

def fib_fib(n):
    if n == 0:
        return 0
    elif n == 1:
        return 0
    elif n == 2:
        return 1

    # Initialize the first two elements of the sequence
    a, b = 0, 0

    # Compute the n-th element iteratively
    for _ in range(3, n + 1):
        a, b = b, a + b

    return b

def vowels_count(s):
    # Define a set of vowels for easy lookup
    vowels = {'a', 'e', 'i', 'o', 'u'}

    # Initialize a counter for vowels
    count = 0

    # Iterate over each character in the string
    for i, char in enumerate(s):
        # Check if the character is a vowel
        if char.lower() in vowels:
            count += 1
        # Check if 'y' is at the end of the string
        elif char.lower() == 'y' and i == len(s) - 1:
            count += 1

    return count

