def total_match(lst1, lst2):
    # Calculate the total number of characters in each list
    total_chars_lst1 = sum(len(s) for s in lst1)
    total_chars_lst2 = sum(len(s) for s in lst2)

    # Compare the total character counts and return the appropriate list
    if total_chars_lst1 <= total_chars_lst2:
        return lst1
    else:
        return lst2

from math import sqrt

def is_product_of_three_distinct_primes(a):
    if a < 2:
        return False

    def is_prime(n):
        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

    primes = [i for i in range(2, int(sqrt(a)) + 1) if is_prime(i)]

    for i in range(len(primes)):
        for j in range(i + 1, len(primes)):
            for k in range(j + 1, len(primes)):
                if primes[i] * primes[j] * primes[k] == a:
                    return True
    return False

# Example usage:
print(is_product_of_three_distinct_primes(30))  # True, because 30 = 2 * 3 * 5
print(is_product_of_three_distinct_primes(60))  # True, because 60 = 2 * 2 * 3 * 5 (but only 2 and 3 are distinct)
print(is_product_of_three_distinct_primes(7))   # False, because 7 is a prime number itself
print(is_product_of_three_distinct_primes(1))   # False, because 1 is not a product of any primes

