def is_prime_length(string):
    # Check if the string is empty
    if not string:
        return False

    # Calculate the length of the string
    length = len(string)

    # Check if the length is less than 2
    if length < 2:
        return False

    # Check for factors from 2 to the square root of the length
    for i in range(2, int(length**0.5) + 1):
        if length % i == 0:
            return False

    # If no factors were found, the length is prime
    return True

def encrypt(s):
    if not s:
        return ""

    encrypted = []
    for char in s:
        if char.isalpha():
            shift = 2
            if char.islower():
                base = ord('a')
            else:
                base = ord('A')

            # Calculate the new character position, wrapping around the alphabet
            new_char = chr((ord(char) - base + shift) % 26 + base)
            encrypted.append(new_char)
        else:
            # Non-alphabetic characters remain unchanged
            encrypted.append(char)

    return ''.join(encrypted)

def next_smallest(lst):
    if not lst:
        return None

    # Convert the list to a set to remove duplicates and then back to a sorted list
    unique_sorted_lst = sorted(set(lst))

    # Check if there are at least two unique elements
    if len(unique_sorted_lst) < 2:
        return None

    # Return the second smallest element
    return unique_sorted_lst[1]

def encode_message(message):
    # Define vowels and their replacements
    vowels = "aeiouAEIOU"
    replacements = {
        'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w',
        'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'
    }

    # Initialize an empty list to store the encoded characters
    encoded_chars = []

    # Iterate over each character in the message
    for char in message:
        if char in vowels:
            # Replace vowel with the corresponding replacement
            encoded_chars.append(replacements[char])
        elif char.isalpha():
            # Swap the case of the letter
            if char.islower():
                encoded_chars.append(char.upper())
            else:
                encoded_chars.append(char.lower())
        else:
            # If the character is not a letter, keep it as is
            encoded_chars.append(char)

    # Join the list into a string and return
    return ''.join(encoded_chars)

# Example usage:
print(encode_message("Hello World"))  # Output: "jGNNQ yQTNF"
