print(encode_message(""))  # Output: ""
print(encode_message("a"))  # Output: "C"
print(encode_message("Zebra"))  # Output: "zCGg"

from math import sqrt

def sum_of_digits_of_largest_prime(lst):
    def is_prime(n):
        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True

    largest_prime = 0
    for num in lst:
        if is_prime(num) and num > largest_prime:
            largest_prime = num

    if largest_prime == 0:
        return 0

    return sum(int(digit) for digit in str(largest_prime))

