def check_dict_case(dict):
    if not dict:
        return False

    all_lowercase = all(key.islower() for key in dict.keys())
    all_uppercase = all(key.isupper() for key in dict.keys())

    return all_lowercase or all_uppercase

def build_stone_pile(n):
    if n <= 0:
        raise ValueError("Input must be a positive integer.")

    if n == 1:
        return [1]

    # Determine the pattern based on whether n is odd or even
    if n % 2 == 0:
        # Even n: Start with 2 stones and increase by 2 for each subsequent level
        return [2 * i for i in range(1, n + 1)]
    else:
        # Odd n: Start with 1 stone and increase by 2 for each subsequent level
        return [2 * i - 1 for i in range(1, n + 1)]

# Example usage:
print(build_stone_pile(3))  # Output: [1, 3, 5]
print(build_stone_pile(4))  # Output: [2, 4, 6, 8]

def biggest_even_in_range(x, y):
    # Check if the range is valid
    if x > y:
        return -1

    # If y is even, return y
    if y % 2 == 0:
        return y

    # If y is odd, check if y-1 is within the range
    if y - 1 >= x:
        return y - 1

    # If no even number is found in the range, return -1
    return -1

def unique_digits(x):
    def has_only_odd_digits(n):
        return all(int(digit) % 2 != 0 for digit in str(n))

    # Filter the list to include only numbers with odd digits
    odd_digit_numbers = [num for num in x if has_only_odd_digits(num)]

    # Sort the filtered list
    odd_digit_numbers.sort()

    return odd_digit_numbers

def count_even_odd_palindromes(n):
    def is_palindrome(num):
        return str(num) == str(num)[::-1]

    even_count = 0
    odd_count = 0

    for i in range(1, n + 1):
        if is_palindrome(i):
            if i % 2 == 0:
                even_count += 1
            else:
                odd_count += 1

    return (even_count, odd_count)

# Example usage:
# print(count_even_odd_palindromes(10))  # Output: (4, 6)

def count_nums(arr):
    def digit_sum(n):
        # Calculate the sum of digits of n, considering the sign
        return sum(int(digit) for digit in str(abs(n)))

    # Count numbers with a positive digit sum
    return sum(1 for num in arr if digit_sum(num) > 0)

def histogram(test):
    if not test:
        return {}

    # Split the input string into individual letters
    letters = test.split()

    # Create a dictionary to store the frequency of each letter
    frequency = {}

    # Count the frequency of each letter
    for letter in letters:
        if letter in frequency:
            frequency[letter] += 1
        else:
            frequency[letter] = 1

    # Find the maximum frequency
    max_frequency = max(frequency.values(), default=0)

    # Create a dictionary to store the letters with the maximum frequency
    result = {letter: count for letter, count in frequency.items() if count == max_frequency}

    return result

def select_words(s, n):
    if n <= 0:
        return []

    vowels = set('aeiouAEIOU')
    words = s.split()
    result = []

    for word in words:
        consonant_count = sum(1 for char in word if char.isalpha() and char not in vowels)
        if consonant_count == n:
            result.append(word)

    return result

def get_closest_vowel(word):
    vowels = "aeiouAEIOU"
    closest_vowel = ""

    # Iterate over the word from the second last character to the second character
    for i in range(len(word) - 2, 0, -1):
        if word[i] in vowels:
            # Check if the previous and next characters are consonants
            if word[i - 1] not in vowels and word[i + 1] not in vowels:
                closest_vowel = word[i]
                break

    return closest_vowel

def can_concatenate_to_balanced(lst):
    # Check if the input list contains exactly two strings
    if len(lst) != 2:
        return "No"

    # Extract the two strings from the list
    str1, str2 = lst

    # Function to check if a single string is balanced
    def is_balanced(s):
        balance = 0
        for char in s:
            if char == '(':
                balance += 1
            elif char == ')':
                balance -= 1
            # If balance goes negative, it means there are more closing than opening
            if balance < 0:
                return False
        # At the end, balance should be zero for the string to be balanced
        return balance == 0

    # Check both possible concatenations
    if is_balanced(str1 + str2) or is_balanced(str2 + str1):
        return "Yes"
    else:
        return "No"

# Example usage:
# print(can_concatenate_to_balanced(["()(", ")"]))  # Output: Yes
# print(can_concatenate_to_balanced([")", ")"]))     # Output: No

def get_odd_collatz(n):
    if n <= 0:
        raise ValueError("Input must be a positive integer.")

    odd_numbers = []

    while n != 1:
        if n % 2 != 0:
            odd_numbers.append(n)
        n = n // 2 if n % 2 == 0 else 3 * n + 1

    odd_numbers.append(1)  # The sequence always ends with 1, which is odd
    odd_numbers.sort()

    return odd_numbers

def split_words(txt):
    # Check if the input is empty
    if not txt:
        return []

    # Check if the input contains whitespace
    if " " in txt:
        return txt.split()

    # Check if the input contains commas
    if "," in txt:
        return txt.split(",")

    # Count the number of lowercase letters with odd order in the alphabet
    count = sum(1 for char in txt if char.islower() and (ord(char) - ord('a')) % 2 == 0)
    return count

def is_sorted(lst):
    # Check if the list is empty or has only one element
    if len(lst) <= 1:
        return True

    # Iterate through the list and check for duplicates
    for i in range(1, len(lst)):
        # If the current element is less than the previous one, it's not sorted
        if lst[i] < lst[i - 1]:
            return False

        # Check for more than one duplicate of the same number
        if i > 1 and lst[i] == lst[i - 1] == lst[i - 2]:
            return False

    return True

def prod_signs(arr):
    if not arr:
        return None

    sign_product = 1
    magnitude_sum = 0

    for num in arr:
        if num == 0:
            return 0
        elif num < 0:
            sign_product *= -1
        magnitude_sum += abs(num)

    return magnitude_sum * sign_product

from typing import List

def find_min_path(grid: List[List[int]], k: int) -> List[int]:
    if not grid or not grid[0]:
        raise ValueError("Grid must be non-empty")

    N = len(grid)
    directions = [(0, 1), (1, 0), (-1, 0), (0, -1)]  # Right, Down, Up, Left

    def dfs(x, y, path):
        if len(path) == k:
            return path

        min_path = None
        for dx, dy in directions:
            nx, ny = x + dx, y + dy
            if 0 <= nx < N and 0 <= ny < N and (nx, ny) not in path:
                new_path = dfs(nx, ny, path + [grid[nx][ny]])
                if new_path is not None:
                    if min_path is None or new_path < min_path:
                        min_path = new_path
        return min_path

    min_path = None
    for i in range(N):
        for j in range(N):
            path = dfs(i, j, [grid[i][j]])
            if path is not None:
                if min_path is None or path < min_path:
                    min_path = path

    return min_path

# Example usage:
# grid = [
#     [1, 2, 3],
#     [4, 5, 6],
#     [7, 8, 9]
# ]
# k = 4
# print(find_min_path(grid, k))  # Output: [1, 2, 3, 1]

def is_nested(string):
    # Initialize a counter for open brackets and a flag to check for nesting
    open_brackets = 0
    has_nesting = False

    # Iterate through each character in the string
    for char in string:
        if char == '[':
            # Increment the open bracket counter
            open_brackets += 1
        elif char == ']':
            # Decrement the open bracket counter
            if open_brackets > 0:
                open_brackets -= 1
                # If there are still open brackets, it means we have nesting
                has_nesting = True
            else:
                # More closing brackets than opening ones, invalid sequence
                return False

    # If we have any open brackets left, it means the sequence is not complete
    if open_brackets > 0:
        return False

    # Return True if there was at least one nesting
    return has_nesting

def can_arrange(arr):
    # If the array is empty or has only one element, return -1
    if len(arr) <= 1:
        return -1

    # Iterate through the array from the second last element to the first
    for i in range(len(arr) - 2, -1, -1):
        # Check if the current element is not greater than or equal to the previous element
        if arr[i] > arr[i + 1]:
            return i

    # If no such index is found, return -1
    return -1

def largest_smallest_integers(lst):
    # Initialize variables to store the largest negative and smallest positive integers
    largest_negative = None
    smallest_positive = None

    # Iterate through each number in the list
    for num in lst:
        if num < 0:
            # Update largest_negative if the current number is larger
            if largest_negative is None or num > largest_negative:
                largest_negative = num
        elif num > 0:
            # Update smallest_positive if the current number is smaller
            if smallest_positive is None or num < smallest_positive:
                smallest_positive = num

    # Return the result as a tuple
    return (largest_negative, smallest_positive)

def compare_real_numbers(a, b):
    def parse_number(value):
        if isinstance(value, str):
            try:
                return float(value)
            except ValueError:
                raise ValueError(f"Invalid input: {value} is not a valid number.")
        elif isinstance(value, (int, float)):
            return value
        else:
            raise TypeError(f"Unsupported type: {type(value)}")

    num_a = parse_number(a)
    num_b = parse_number(b)

    if num_a > num_b:
        return a
    elif num_b > num_a:
        return b
    else:
        return None

from math import sqrt

def is_prime(n):
    """Check if a number is prime."""
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def filter_prime_length_words(sentence):
    """Return words from the sentence whose lengths are prime numbers."""
    words = sentence.split()
    prime_length_words = [word for word in words if is_prime(len(word))]
    return ' '.join(prime_length_words)

# Example usage:
print(filter_prime_length_words("This is a test sentence"))  # Output: "is a"
print(filter_prime_length_words("Hello world"))  # Output: "Hello"
print(filter_prime_length_words(""))  # Output: ""
print(filter_prime_length_words("a"))  # Output: "a"
print(filter_prime_length_words("prime"))  # Output: "prime"

def order_by_points(nums):
    # Helper function to calculate the sum of digits of a number
    def digit_sum(n):
        return sum(int(digit) for digit in str(abs(n)))

    # Sort the list using a stable sort that maintains the original order for equal elements
    return sorted(nums, key=digit_sum)

# Example usage:
print(order_by_points([56, 34, 12, 89, 23]))  # Output: [12, 23, 34, 56, 89]
print(order_by_points([-12, -34, -56]))       # Output: [-12, -34, -56]
print(order_by_points([]))                    # Output: []
print(order_by_points([5]))                     # Output: [5]

def specialFilter(nums):
    def is_odd_digit(digit):
        return digit % 2 != 0

    def has_odd_first_and_last_digits(num):
        num_str = str(abs(num))
        first_digit = int(num_str[0])
        last_digit = int(num_str[-1])
        return is_odd_digit(first_digit) and is_odd_digit(last_digit)

    count = 0
    for num in nums:
        if num > 10 and has_odd_first_and_last_digits(num):
            count += 1
    return count

# Edge cases
print(specialFilter([]))          # Output: 0
print(specialFilter([11]))         # Output: 1
print(specialFilter([111, 222, 333, 444, 555]))  # Output: 5

def is_prime(n):
    """Check if a number is prime."""
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def prime_or_not(n, x, y):
    """
    Returns x if n is a prime number, otherwise returns y.

    :param n: Integer to check for primality.
    :param x: Integer to return if n is prime.
    :param y: Integer to return if n is not prime.
    :return: x if n is prime, otherwise y.
    """
    if not isinstance(n, int) or not isinstance(x, int) or not isinstance(y, int):
        raise TypeError("All inputs must be integers.")
    if n < 0:
        raise ValueError("Input must be a non-negative integer.")
    return x if is_prime(n) else y

# Example usage:
# print(prime_or_not(7, 100, 200))  # Output: 100
# print(prime_or_not(4, 100, 200))  # Output: 200

def find_max(words):
    if not words:
        return ""

    max_unique_count = 0
    result_word = ""

    for word in words:
        unique_chars = set(word)
        unique_count = len(unique_chars)

        if unique_count > max_unique_count or (unique_count == max_unique_count and word < result_word):
            max_unique_count = unique_count
            result_word = word

    return result_word

def evaluate_expression(operator, operand):
    if len(operator) != len(operand) - 1:
        raise ValueError("The length of the operator list must be one less than the length of the operand list.")

    if len(operand) < 2:
        raise ValueError("The operand list must contain at least two operands.")

    if len(operator) < 1:
        raise ValueError("The operator list must contain at least one operator.")

    # Start with the first operand
    result = operand[0]

    # Iterate over the operators and operands
    for i, op in enumerate(operator):
        if op == '+':
            result += operand[i + 1]
        elif op == '-':
            result -= operand[i + 1]
        elif op == '*':
            result *= operand[i + 1]
        elif op == '//':
            result //= operand[i + 1]
        elif op == '**':
            result **= operand[i + 1]
        else:
            raise ValueError(f"Unsupported operator: {op}")

    return result

# Example usage:
# print(evaluate_expression(['+', '*', '-'], [3, 4, 5, 2]))  # Output: 9

def solve(s):
    # Check if the string contains any letters
    contains_letters = any(char.isalpha() for char in s)

    if contains_letters:
        # Reverse the case of each letter
        return ''.join(char.swapcase() if char.isalpha() else char for char in s)
    else:
        # Reverse the entire string
        return s[::-1]
